def n_gram_tokens(s):
    s = normalize_arabic(s)
    return s.split()

def token_f1(a,b):
    ta = n_gram_tokens(a)
    tb = n_gram_tokens(b)
    ca = collections.Counter(ta)
    cb = collections.Counter(tb)
    common = sum((ca & cb).values())
    prec = common / (len(tb) or 1)
    rec = common / (len(ta) or 1)
    if prec+rec == 0:
        f1 = 0.0
    else:
        f1 = 2*prec*rec/(prec+rec)
    return {'precision':prec,'recall':rec,'f1':f1, 'common':common, 'len_a':len(ta), 'len_b':len(tb)}

